import { CSSResult, html, nothing } from 'lit';
import { util } from '../../internal/utils.js';
import { classMap } from 'lit/directives/class-map.js';
import XDragPanel from '../panel/drag-panel.component.js';
import styles from './window.style.js';

/**
 * XWindow — 弹窗组件，支持拖拽、最大化、最小化、关闭以及边缘拖拽缩放。
 *
 * <h3>继承链</h3>
 * <pre>
 *   XUIElement → XPanel → XDragPanel → XWindow
 * </pre>
 *
 * <h3>核心功能</h3>
 * <ul>
 *   <li><b>拖拽移动</b> — 通过父类 {@link XDragPanel.dragPanel} 实现 header 拖拽</li>
 *   <li><b>最大化/还原</b> — 双击 header 或点击最大化按钮切换全屏与原始尺寸</li>
 *   <li><b>内容渲染</b> — {@link content} / {@link load} / {@link iframe} 三种内容加载方式</li>
 *   <li><b>边缘缩放</b> — 右边缘拖拽改变宽度，底边缘拖拽改变高度</li>
 *   <li><b>CSS resize</b> — 浏览器原生右下角缩放句柄作为补充</li>
 *   <li><b>ResizeObserver</b> — 窗口尺寸变化时向内容区派发 {@code resize} 事件</li>
 * </ul>
 *
 * <h3>默认配置</h3>
 * <pre>
 *   view: 'normal'     — 初始视图模式（normal / maximize）
 *   park: 'center'     — 初始定位（center / top / left / …）
 *   draggable: true    — header 拖拽
 *   minimize: true     — 显示最小化按钮
 *   maximize: true     — 显示最大化按钮
 *   closable: true     — 显示关闭按钮
 *   resize: true       — 允许缩放
 *   visible: false     — 初始隐藏
 *   destroy: false     — 关闭时是否移除 DOM
 * </pre>
 */
export default class XWindow extends XDragPanel {
  static styles: CSSResult = styles;
  static defaultOptions = { view: 'normal', park: 'center', draggable: true, minimize: true, maximize: true, closable: true, resize: true, visible: false, header: { height: 24 }, footer: { height: 0 }, border: false };

  /**
   * 窗口尺寸变化观察器。
   *
   * <p>当 XWindow 宿主元素尺寸发生变化（包括 CSS resize、边缘拖拽缩放、
   * 最大化/还原等操作引起的变化）时，向窗口元素派发 {@code resize} 事件，
   * 内容区可以监听该事件自行调整布局。</p>
   */
  private observer = new ResizeObserver(() => {
    /** XWindow的窗口大小变化时,对内容触发resize事件 */
    util.trigger(this, 'resize');
  });

  /**
   * 直接传入 HTML 字符串并渲染到窗口内容区。
   *
   * <p>清空当前 innerHTML，创建一个绝对定位的 {@code <div>} 容器包裹传入的 HTML，
   * 确保内容在 Header 之下的可用区域内正确显示，避免高度溢出。</p>
   *
   * <p>与 {@link load}（从 URL 通过 EasyUI 加载）和 {@link iframe}（iframe 嵌入）并列，
   * 适用于已持有 HTML 字符串的场景（如动态生成的表单、弹窗配置等）。</p>
   *
   * <p>传入的 {@code incoming} 对象会挂载到 XWindow 元素的 {@code incoming} 属性上，
   * 供 HTML 内的 inline 脚本通过
   * <pre>this.closest('x-window').incoming</pre>
   * 访问外部上下文数据。{@code incoming} 中既可包含普通值也可包含方法，
   * 内部 HTML 通过 <pre>this.closest('x-window').incoming.loadJson()</pre>
   * 即可调用外部传入的方法。</p>
   *
   * @param html     要渲染的 HTML 字符串，为空时直接返回
   * @param incoming 可选的外部数据/方法对象，挂载为 {@code incoming} 供 inline 脚本使用
   */
  public content(html: string, incoming?: Record<string, any>) {
    if (util.isBlank(html)) return;
    this.innerHTML = '';
    const element = document.createElement('div');
    util.setStyle(element, { position: 'absolute', inset: '0px' });
    if (incoming) {
      (this as any).incoming = incoming;
    }
    (this as HTMLElement).appendChild(element);
    element.innerHTML = html;
  }

  /**
   * 返回当前窗口的 incoming 数据/方法对象。
   *
   * @returns 通过 {@link content} 传入的 incoming 对象，未设置时返回 {@code undefined}
   */
  public getIncoming(): Record<string, any> | undefined {
    return (this as any).incoming;
  }

  /**
   * 打开窗口：将窗口元素加入 {@code document.body} 并显示。
   *
   * <p>执行流程：</p>
   * <ol>
   *   <li>若自身 id 非空，先移除 body 中同 id 的已有窗口，保证单例</li>
   *   <li>将自身 {@code appendChild} 到 {@code document.body}</li>
   *   <li>调用 {@link show} 执行定位与可见性切换</li>
   *   <li>若传入 {@code afterOpen} 回调，在最后自动调用，参数为窗口自身</li>
   * </ol>
   *
   * @param afterOpen 可选回调，窗口打开后自动调用，接收窗口元素作为参数
   */
  public open(afterOpen?: (win: XWindow) => void) {
    if (this.id) {
      const exist = document.body.querySelector(`#${this.id}`);
      if (exist) exist.remove();
    }
    document.body.appendChild(this);
    this.show();
    if (afterOpen) {
      afterOpen(this);
    }
  }

  /**
   * 最小化按钮点击回调。
   *
   * <p>当前为空实现，子类可覆盖以实现自定义最小化行为
   * （如收缩到任务栏、动画过渡等）。</p>
   *
   * @param _e 鼠标事件（未使用）
   */
  public minimize(_e: MouseEvent) {
    this.hide();
  }

  /**
   * 最大化 / 还原 切换。
   *
   * <h4>最大化</h4>
   * <ul>
   *   <li>保存当前 left / top / width / height 到 {@code this.data}</li>
   *   <li>设置窗口尺寸为父容器尺寸（撑满父级）</li>
   *   <li>将 view 选项切换为 {@code 'maximize'}</li>
   * </ul>
   *
   * <h4>还原</h4>
   * <ul>
   *   <li>从 {@code this.data} 恢复保存的 left / top / width / height</li>
   *   <li>将 view 选项切换回 {@code 'normal'}</li>
   * </ul>
   *
   * @param _e 鼠标事件（双击 header 或点击最大化按钮触发）
   */
  public maximize(_e: MouseEvent) {
    if (this.options.view === 'normal') {
      this.setOption('view', 'maximize');
      this.data = { left: this.offsetLeft, top: this.offsetTop, width: this.offsetWidth, height: this.offsetHeight };
      const parent = this.parentElement;
      if (parent) {
        this.setHostStyle({ width: parent.offsetWidth + 'px', height: parent.offsetHeight + 'px' });
      }
    } else {
      this.setOption('view', 'normal');
      this.setHostStyle({ left: this.data.left + 'px', top: this.data.top + 'px', width: this.data.width + 'px', height: this.data.height + 'px' });
    }
    this.requestUpdate();
  }

  /**
   * 显示窗口：根据 {@code park} 选项定位窗口，并切换可见性。
   *
   * <p>若配置了 {@code park} 选项（如 {@code 'center'}），调用 {@link util.setPosition}
   * 将窗口居中定位。若之前为隐藏状态（{@code visible: false}），
   * 设置 CSS visibility 为 {@code 'visible'} 并更新选项标记。</p>
   */
  public show() {
    if (this.hasOption('park')) {
      util.setPosition(this, this.options.park);
    }
    this.setHostStyle({ visibility: 'visible', display: 'block' });
    this.setOption('visible', true);
  }

  /**
   * 隐藏窗口：将 CSS visibility 设为 {@code 'hidden'}。
   *
   * <p>仅在当前可见（{@code visible: true}）时执行，避免重复操作。
   * 与 {@link close} 不同，hide 不移除 DOM 元素。</p>
   */
  public hide() {
    if (this.hasOption('visible', true)) {
      this.setHostStyle({ visibility: 'hidden', display: 'none' });
      this.setOption('visible', false);
    }
  }

  /**
   * 关闭窗口。
   *
   * <ul>
   *   <li>若 {@code options.destroy == true} — 从父节点移除 DOM 元素，彻底销毁</li>
   *   <li>否则 — 仅隐藏窗口（调用 {@link hide} 逻辑），保留 DOM 以便复用</li>
   * </ul>
   */
  public close() {
    if (this.options.destroy == true) {
      this.parentNode?.removeChild(this);
    } else {
      this.setHostStyle({ visibility: 'hidden', display: 'none' });
    }
  }

  /**
   * 从右边缘拖拽改变窗口宽度。
   *
   * <h4>交互流程</h4>
   * <ol>
   *   <li><b>mousedown</b> — 记录初始鼠标 X 坐标和窗口宽度/高度，
   *       保存当前 {@code overflow} 样式值，保存全局 mousemove/mouseup 处理器</li>
   *   <li><b>mousemove</b> — 将宿主 overflow 切换为 {@code 'visible'}（防止出现滚动条），
   *       根据鼠标位移计算新宽度（下限 100px），通过 mask 遮罩实时预览窗口轮廓</li>
   *   <li><b>mouseup</b> — 应用最终宽度到宿主元素，恢复原始 overflow 值，
   *       隐藏 mask 遮罩，还原全局事件处理器</li>
   * </ol>
   *
   * <h4>设计要点</h4>
   * <ul>
   *   <li>mask 遮罩定位使用相对于 body 的绝对坐标（{@code win.offsetLeft / offsetTop}），
   *       确保遮罩始终覆盖在实际窗口位置</li>
   *   <li>拖拽过程中动态切换 overflow 为 {@code 'visible'}，避免宿主出现滚动条干扰拖拽体验；
   *       mouseup 时恢复原始 overflow 值</li>
   *   <li>保存/恢复 {@code document.onmousemove/onmouseup} 的原有处理器，
   *       避免与其他组件的拖拽逻辑冲突</li>
   *   <li>最小宽度限制为 100px，与 CSS {@code min-width} 保持一致</li>
   * </ul>
   *
   * @param e 鼠标按下事件（由 .main-right 元素的 @mousedown 触发）
   */
  public resizeRight(e: MouseEvent) {
    if (!this.options.resize) return;
    e.preventDefault();
    e.stopPropagation();

    const win = this as HTMLElement;
    const mask = this.getMask();
    const initX = e.clientX;
    const initWidth = this.offsetWidth;
    const initHeight = this.offsetHeight;
    const overflow = this.style.overflow;
    let newWidth = initWidth;

    const omm = document.onmousemove;
    const omu = document.onmouseup;

    document.onmousemove = (o: MouseEvent) => {
      o.preventDefault();
      this.setHostStyle({ overflow: 'visible' });
      newWidth = initWidth + o.clientX - initX;
      if (newWidth < 100) newWidth = 100;
      util.setStyle(mask, {
        left: win.offsetLeft + 'px',
        top: win.offsetTop + 'px',
        width: newWidth + 'px',
        height: initHeight + 'px',
        visibility: 'visible',
      });
    };

    document.onmouseup = () => {
      this.setHostStyle({ width: newWidth + 'px', overflow: overflow });
      util.setStyle(mask, { left: '0px', top: '0px', width: '0px', height: '0px', visibility: 'hidden' });
      document.onmousemove = omm;
      document.onmouseup = omu;
    };
  }

  /**
   * 从底边缘拖拽改变窗口高度。
   *
   * <h4>交互流程</h4>
   * <ol>
   *   <li><b>mousedown</b> — 记录初始鼠标 Y 坐标和窗口宽度/高度，
   *       保存当前 {@code overflow} 样式值，保存全局 mousemove/mouseup 处理器</li>
   *   <li><b>mousemove</b> — 将宿主 overflow 切换为 {@code 'visible'}，
   *       根据鼠标位移计算新高度（下限 50px），通过 mask 遮罩实时预览</li>
   *   <li><b>mouseup</b> — 应用最终高度和宽度到宿主元素（mouseup 时重新设置宽度
   *       以防止拖拽过程中宽度被意外改变），恢复原始 overflow 值，
   *       隐藏 mask 遮罩，还原全局事件处理器</li>
   * </ol>
   *
   * <h4>设计要点</h4>
   * <ul>
   *   <li>mouseup 时同时设置 {@code width} 和 {@code height}，确保拖拽过程中
   *       宽度未被其他因素修改</li>
   *   <li>拖拽过程中动态切换 overflow 为 {@code 'visible'}，避免宿主出现滚动条</li>
   *   <li>保存/恢复全局事件处理器，避免与 {@link dragPanel} 等其他拖拽逻辑冲突</li>
   *   <li>最小高度限制为 50px，与 CSS {@code min-height} 保持一致</li>
   * </ul>
   *
   * @param e 鼠标按下事件（由 .main-bottom 元素的 @mousedown 触发）
   */
  public resizeBottom(e: MouseEvent) {
    if (!this.options.resize) return;
    e.preventDefault();
    e.stopPropagation();

    const win = this as HTMLElement;
    const mask = this.getMask();
    const initY = e.clientY;
    const initWidth = this.offsetWidth;
    const initHeight = this.offsetHeight;
    const overflow = this.style.overflow;
    let newHeight = initHeight;

    const omm = document.onmousemove;
    const omu = document.onmouseup;

    document.onmousemove = (o: MouseEvent) => {
      o.preventDefault();
      this.setHostStyle({ overflow: 'visible' });
      newHeight = initHeight + o.clientY - initY;
      if (newHeight < 50) newHeight = 50;
      util.setStyle(mask, {
        left: win.offsetLeft + 'px',
        top: win.offsetTop + 'px',
        width: initWidth + 'px',
        height: newHeight + 'px',
        visibility: 'visible',
      });
    };

    document.onmouseup = () => {
      this.setHostStyle({ width: initWidth + 'px', height: newHeight + 'px', overflow: overflow });
      util.setStyle(mask, { left: '0px', top: '0px', width: '0px', height: '0px', visibility: 'hidden' });
      document.onmousemove = omm;
      document.onmouseup = omu;
    };
  }

  /**
   * Lit 生命周期 — 更新前回调。
   *
   * <p>根据 {@code options.resize} 的值设置宿主元素的 CSS {@code resize} 属性：</p>
   * <ul>
   *   <li>{@code true} — 设为 {@code 'both'}，启用浏览器原生右下角缩放句柄</li>
   *   <li>其他值 — 设为 {@code 'none'}，禁用浏览器原生缩放（边缘拖拽缩放不受影响）</li>
   * </ul>
   *
   * <p>浏览器原生 {@code resize: both} 提供右下角缩放作为边缘拖拽缩放的补充，
   * 两者可以共存。调用父类 {@code super.willUpdate()} 处理 panel 层级的定位逻辑。</p>
   */
  willUpdate(): void {
    super.willUpdate();
    if (this.options.resize === true) {
      this.setHostStyle({ resize: 'both' });
    } else {
      this.setHostStyle({ resize: 'none' });
    }
  }

  /**
   * Lit 生命周期 — 渲染回调。
   *
   * <p>在父类渲染完成后，根据 {@code visible} 选项同步宿主元素的 CSS visibility：</p>
   * <ul>
   *   <li>{@code visible: true} — 确保宿主可见</li>
   *   <li>{@code visible: false} — 确保宿主隐藏</li>
   * </ul>
   *
   * <p>此处的 visibility 同步是为了在 Lit 重渲染后保持可见状态与选项一致，
   * 避免渲染周期中的状态丢失。</p>
   *
   * @returns 父类渲染结果的透传
   */
  render() {
    const result = super.render();
    if (this.hasOption('visible', true)) {
      this.setHostStyle({ visibility: 'visible', display: 'block' });
    } else if (this.hasOption('visible', false)) {
      this.setHostStyle({ visibility: 'hidden', display: 'none' });
    }
    return result;
  }

  /**
   * 渲染窗口右上角的操作按钮。
   *
   * <p>根据选项配置按需渲染以下按钮：</p>
   * <ul>
   *   <li><b>最小化</b> — {@code i.x-minimize}，点击触发 {@link minimize}</li>
   *   <li><b>最大化/还原</b> — CSS 类在 {@code x-maximize} 与 {@code x-restore}
   *       之间根据当前 view 模式切换，点击触发 {@link maximize}</li>
   *   <li><b>关闭</b> — {@code i.x-close}，点击触发 {@link close}</li>
   * </ul>
   *
   * @returns Lit {@code html} 模板结果
   */
  _uiActions() {
    return html`
      ${this.options.minimize ? html`<i class="x-minimize" @click="${this.minimize}"></i>` : nothing}
      ${this.options.maximize ? html`<i class="${classMap({ 'x-maximize': this.hasOption('view', 'normal'), 'x-restore': this.hasOption('view', 'maximize') })}" @click="${this.maximize}"></i>` : nothing}
      ${this.options.closable ? html`<i class="x-close" @click="${this.close}"></i>` : nothing}
    `;
  }

  /**
   * 渲染窗口主体区域结构。
   *
   * <h4>分区布局</h4>
   * <pre>
   *   ┌─── header ──────────────────────────────┐
   *   │ .main-left │ .main-content │ .main-right │  ← 内容行
   *   │            │               │              │
   *   ├────────────┴───────────────┴──────────────┤
   *   │              .main-bottom                  │  ← 底边缘
   *   └────────────────────────────────────────────┘
   * </pre>
   *
   * <ul>
   *   <li><b>.main-left</b> — 左边缘装饰条（2px），当 {@code options.resize} 匹配
   *       {@code 'left'} 时附加 {@code ew-resize} 光标样式</li>
   *   <li><b>.main-right</b> — 右边缘拖拽手柄（2px），绑定 {@link resizeRight}，
   *       始终显示 {@code ew-resize} 双向箭头光标</li>
   *   <li><b>.main-content</b> — 内容区，包含默认 slot，内容通过
   *       {@link content} / {@link load} / {@link iframe} 加载</li>
   *   <li><b>.main-bottom</b> — 底边缘拖拽手柄（2px），绑定 {@link resizeBottom}，
   *       始终显示 {@code ns-resize} 上下箭头光标</li>
   * </ul>
   *
   * @returns Lit {@code html} 模板结果
   */
  _uiMain() {
    return html`
      <div class="${classMap({ 'main-left': true, 'ew-resize': this.hasOption('resize', true, 'left') })}"></div>
      <div class="${classMap({ 'main-right': true, 'ew-resize': this.hasOption('resize', true, 'right') })}" @mousedown="${this.resizeRight}"></div>
      <div class="main-content">
        <slot></slot>
      </div>
      <div class="${classMap({ 'main-bottom': true, 'ns-resize': this.hasOption('resize', true, 'bottom') })}" @mousedown="${this.resizeBottom}"></div>
    `;
  }

  /**
   * 自定义元素挂载到 DOM 时的回调。
   *
   * <p>调用父类的 {@code connectedCallback} 完成 panel 层级的初始化，
   * 然后启动 {@link observer}（ResizeObserver）监听窗口尺寸变化。</p>
   */
  connectedCallback() {
    super.connectedCallback();
    this.observer.observe(this);
  }

  /**
   * 自定义元素从 DOM 卸载时的回调。
   *
   * <p>停止 {@link observer} 对窗口元素的尺寸监听，
   * 然后调用父类的 {@code disconnectedCallback} 完成清理。</p>
   */
  disconnectedCallback(): void {
    super.disconnectedCallback();
    this.observer.unobserve(this);
  }
}
