import { util } from './utils.js';
/**
 * 使用jQuery的官方类型定义, 不能够使用常规的import方式, 因为编译时会将jQuery重命名
 * a.  在文件顶部添加定义：
 *    ///<reference types="jquery" />
 * b. tsconfig.json配置中添加：
 *    "compilerOptions": {
 *      "typeRoots": ["node_modules/@types"],
 *      "types": ["jquery"]
 *    }
 */

export namespace shell {
  export function changeHashURI(url: string) {
    if (util.isBlank(url)) return;

    const baseUrl = document.querySelector('base')?.getAttribute('href');
    if (url.startsWith('#')) {
      if (baseUrl) {
        window.location.href = baseUrl + url;
      } else {
        window.location.href = url;
      }
    } else {
      if (baseUrl) {
        window.location.href = baseUrl + '#' + url;
      } else {
        window.location.href = '#' + url;
      }
    }
  }

  /**
   * 通过jQuery.load()将页面加载进指定id的元素的innerHTML中
   *
   * @param id
   * @param uri
   * @returns
   */
  export function loadMainContent(id: string, uri: string) {
    if (util.isBlank(id)) return;
    const qid = id.startsWith('#') ? id : '#' + id;

    const baseUrl = document.querySelector('base')?.getAttribute('href');
    if (util.isBlank(uri)) {
      if (window.location.hash) {
        let href = '';
        const hash = window.location.hash.substring(1);
        if (hash.startsWith('/')) {
          if (window.location.port) {
            href = window.location.protocol + '//' + window.location.host + ':' + window.location.port + hash;
          } else {
            href = window.location.protocol + '//' + window.location.host + hash;
          }
        } else {
          href = baseUrl + hash;
        }
        util.euiLoad(qid, href);
      } else {
        util.euiLoad(qid, baseUrl + 'netmarkets/home/welcome.html');
      }
    } else {
      util.euiLoad(qid, baseUrl + uri);
    }
  }

  /**
   * EasyUI渲染生成的元素都在"xui-app-footer"之后；
   * 在重新加载"xui-app-content"之前，清理"xui-app-footer"后面所有的元素，
   */
  export function clearFooter(selector: string) {
    const footer = document.querySelector(selector);
    if (footer) {
      util.nextAll(footer).map((el: Element) => el.remove());
    }
  }
}
