import { css } from 'lit';
import componentStyles from '../../styles/component.styles';

export default css`
  ${componentStyles}
  :host {
    display: block;
    position: absolute;
    overflow: visible;
  }
  .x-root {
    display: flex;
    align-items: center;
  }
  .row {
    flex-direction: row;
    height: 100%;
  }
  .column {
    flex-direction: column;
    width: 100%;
  }
`;
