import { CSSResult, html } from 'lit';
import { util } from '../../internal/utils.js';
import XUIElement from '../../internal/abstract.js';
import styles from './layout.style.js';

export default class XLayout extends XUIElement {
  static styles: CSSResult = styles;
  static defaultOptions = { park: 'fit', border: true };

  willUpdate(): void {
    super.willUpdate();
    if (this.options.park == 'fit') {
      util.setPosition(this, this.options.park);
    }
  }

  private slotChange(o) {
    /** 设置center slot的子元素的height:100% */
    o.target.assignedNodes().forEach((element) => {
      const slot = element.getAttribute('slot');
      if (!util.isBlank(slot)) {
        util.setStyle(element, { position: 'relative' });
        if (slot === 'center') {
          util.setStyle(element, { position: 'absolute', inset: '0px' });
        }
        if (this.hasOption('border', true)) {
          const parent = o.target.parentElement;
          if (parent) {
            util.addClass(parent, "border");
          }
        }
      }
    });
  }

  render() {
    return html`
      <div class="x-root">
        <header><slot name="north" @slotchange=${this.slotChange}></slot></header>
        <main>
          <div class="east"><slot name="east" @slotchange=${this.slotChange}></slot></div>
          <div class="center"><slot name="center" @slotchange=${this.slotChange}></slot></div>
          <div class="west"><slot name="west" @slotchange=${this.slotChange}></slot></div>
        </main>
        <footer><slot name="south" @slotchange=${this.slotChange}></slot></footer>
      </div>
    `;
  }
}
