import { CSSResult, html } from 'lit';
import { property } from 'lit/decorators.js';
import { classMap } from 'lit/directives/class-map.js';
import { ifDefined } from 'lit/directives/if-defined.js';
import styles from './button.style.js';
import XUIElement from '../../internal/abstract.js';

export default class XButton extends XUIElement {
  static styles: CSSResult = styles;

  static defaultOptions = {
    hotKey: '',
    caret: false,
    style: '',
    border: 'fillet', //border:'fillet'|'square'|'ellipse'|'none'
  };

  @property({ type: Boolean }) selected = false;

  render() {
    if (this.selected) {
      this.setHostStyle({ background: 'rgba(227, 250, 212, 0.51)' });
    } else {
      this.setHostStyle({ background: '' });
    }
    return html`<div class="x-root">
      <button
        part="btn"
        style="${ifDefined(this.options.style)}"
        class="${classMap({
          none: this.options.border == 'none',
          fillet: this.options.border == 'fillet',
          square: this.options.border == 'square',
          ellipse: this.options.border == 'ellipse',
        })}"
      >
        <slot></slot>
        ${this.options.caret ? html`<i part="caret" class="fa caret-down"></i>` : ''}
      </button>
      <slot name="subfix"></slot>
    </div>`;
  }
}
