import { CSSResult, html } from 'lit';
import { ifDefined } from 'lit/directives/if-defined.js';
import { classMap } from 'lit/directives/class-map.js';
import { XItem } from '../../internal/types.js';
import { util } from '../../internal/utils.js';
import XPanel from './panel.component.js';
import styles from './tab-panel.style.js';
import { OnSelectEvent } from '../../internal/events.js';

export default class XTabPanel extends XPanel {
  static styles: CSSResult = styles;
  static defaultOptions = { park: 'top', draggable: false, header: { height: 28 }, footer: { height: 0 }, params: {}, closable: false, border: false };
  static customEvents = { 'o-select': OnSelectEvent };

  /** 将 tools / infos 两个具名插槽追加到父类 slotController 的监听列表中 */
  constructor() {
    super();
    this.slotController.slotNames.push('tools', 'infos');
  }

  public getSelected() {
    for (const item of this.data as Array<XItem>) {
      if (item.selected) {
        if (item.element instanceof XPanel) {
          return item.element;
        }
      }
    }
  }

  private active(tab: XItem) {
    if (tab.selected === true) return;
    (this.data as Array<XItem>).forEach((item: XItem) => {
      item.selected = false;
    });
    tab.selected = true;
    this.data = [...this.data];
    /** Tab激活后, 激发o-select事件 */
    this.emit('o-select');

    if (tab.loaded != true) {
      if (tab.element instanceof XPanel) {
        (tab.element as XPanel).refresh();
        tab.loaded = true;
      }
    }
  }

  private handleMainChange() {
    if (this.data == void 0) this.data = [];
    this.data.splice(0, this.data.length); //清空
    const panels = this.querySelectorAll('x-panel');
    for (const panel of panels) {
      if (util.isBlank(panel.slot)) {
        this.data.push({ name: this.toS(panel.name), icon: panel.icon, display: panel.title, url: this.toS(panel.options.url), element: panel });
      }
    }
    this.requestUpdate();
    if (this.data.length > 0) {
      this.active(this.data[0]);
    }
  }

  /**
   * 组件渲染完成后，根据item.selected属性显示和隐藏对应Tab的XPanel
   */
  protected updated(): void {
    for (const item of this.data as Array<XItem>) {
      if (item.selected) {
        if (item.element instanceof XPanel) {
          const panel = item.element as XPanel;
          panel.show();
          // x-composer锁定时触发resize会导致隐藏panel中的组件计算尺寸为0而折叠，
          // 在panel显示后触发resize让其内部组件重新计算布局
          util.trigger(panel, 'resize');
        }
      } else {
        if (item.element instanceof XPanel) {
          (item.element as XPanel).hide();
        }
      }
    }
  }

  _uiHeader() {
    if (this.data == void 0) this.data = [];

    return html`<div class="line-bottom" style="left:0px;width:10px;"></div>
      <div class="tab-header">
        ${this.slotController.test('tools')
          ? html`<div class="tab-left">
              <slot name="tools" style="display:inline-block;float:left;"></slot>
            </div>`
          : ''}
        <ul id="tab-items">
          ${(this.data as Array<XItem>).map(
            (item: XItem) =>
              html`<li class="${classMap({ 'line-bottom': true, selected: item.selected == true })}" @click="${() => this.active(item)}">
                <x-cell icon="${ifDefined(item.icon)}" title="${ifDefined(item.display)}"></x-cell>
              </li>`,
          )}
        </ul>
        ${this.slotController.test('infos')
          ? html`<div class="tab-right">
              <slot name="infos"></slot>
            </div>`
          : ''}
      </div>
      <div class="line-bottom" style="right:0px;width:10px;"></div>`;
  }

  _uiMain() {
    return html`<slot @slotchange=${this.handleMainChange}></slot>`;
  }

  disconnectedCallback(): void {
    super.disconnectedCallback();
  }
}
